SELECT o.id, o.outbound_no, o.outbound_type, o.warehouse_id, w.warehouse_name, o.requester_id, u.real_name AS requester_name, o.target_org_id, torg.org_name AS target_org_name, o.purpose, o.source_order_id, o.source_order_no, o.total_amount, o.remark, o.attachments, o.status, o.submitted_at, o.submitted_by, COALESCE(sub.real_name, sub.username) AS submitter_name, o.approved_at, o.approved_by, o.completed_at, COALESCE(apr.real_name, apr.username) AS approver_name, o.approve_remark, o.org_id, org.org_name, o.created_at, o.updated_at, COUNT(i.id) AS item_count, COALESCE(SUM(i.quantity), 0) AS total_quantity, (SELECT GROUP_CONCAT(DISTINCT w2.warehouse_name SEPARATOR '、') FROM wms_outbound_order_item i2 LEFT JOIN wms_warehouse w2 ON w2.id = i2.warehouse_id AND w2.deleted = 0 WHERE i2.outbound_id = o.id ) AS warehouse_names FROM wms_outbound_order o LEFT JOIN wms_outbound_order_item i ON i.outbound_id = o.id LEFT JOIN wms_warehouse w ON w.id = o.warehouse_id AND w.deleted = 0 LEFT JOIN auth_user u ON u.id = o.requester_id LEFT JOIN auth_user sub ON sub.id = o.submitted_by LEFT JOIN auth_user apr ON apr.id = o.approved_by LEFT JOIN sys_organization org ON org.id = o.org_id AND org.deleted = 0 LEFT JOIN sys_organization torg ON torg.id = o.target_org_id AND torg.deleted = 0 WHERE o.deleted = 0
AND o.outbound_no LIKE CONCAT('%', #{q.outboundNo}, '%')
AND o.outbound_type = #{q.outboundType}
AND o.status = #{q.status}
AND o.warehouse_id = #{q.warehouseId}
AND o.org_id = #{q.orgId}
AND o.org_id IN
#{oid}
AND DATE(o.created_at) >= #{q.startDate}
AND DATE(o.created_at) <= #{q.endDate}
GROUP BY o.id ORDER BY o.created_at DESC

SELECT o.id, o.outbound_no, o.outbound_type, o.warehouse_id, w.warehouse_name, o.requester_id, u.real_name AS requester_name, o.target_org_id, torg.org_name AS target_org_name, o.purpose, o.source_order_id, o.source_order_no, o.total_amount, o.remark, o.attachments, o.status, o.submitted_at, o.submitted_by, COALESCE(sub.real_name, sub.username) AS submitter_name, o.approved_at, o.approved_by, o.completed_at, COALESCE(apr.real_name, apr.username) AS approver_name, o.approve_remark, o.org_id, org.org_name, o.created_at, o.updated_at, COUNT(i.id) AS item_count, COALESCE(SUM(i.quantity), 0) AS total_quantity, (SELECT GROUP_CONCAT(DISTINCT w2.warehouse_name SEPARATOR '、') FROM wms_outbound_order_item i2 LEFT JOIN wms_warehouse w2 ON w2.id = i2.warehouse_id AND w2.deleted = 0 WHERE i2.outbound_id = o.id ) AS warehouse_names FROM wms_outbound_order o LEFT JOIN wms_outbound_order_item i ON i.outbound_id = o.id LEFT JOIN wms_warehouse w ON w.id = o.warehouse_id AND w.deleted = 0 LEFT JOIN auth_user u ON u.id = o.requester_id LEFT JOIN auth_user sub ON sub.id = o.submitted_by LEFT JOIN auth_user apr ON apr.id = o.approved_by LEFT JOIN sys_organization org ON org.id = o.org_id AND org.deleted = 0 LEFT JOIN sys_organization torg ON torg.id = o.target_org_id AND torg.deleted = 0 WHERE o.deleted = 0
AND o.outbound_no LIKE CONCAT('%', #{q.outboundNo}, '%')
AND o.outbound_type = #{q.outboundType}
AND o.status = #{q.status}
AND o.warehouse_id = #{q.warehouseId}
AND o.org_id = #{q.orgId}
AND o.org_id IN
#{oid}
AND DATE(o.created_at) >= #{q.startDate}
AND DATE(o.created_at) <= #{q.endDate}
GROUP BY o.id ORDER BY o.created_at DESC

SELECT EXISTS(
    SELECT 1
    FROM wms_outbound_order o
    WHERE o.deleted = 0
      AND o.warehouse_id = #{warehouseId}
      AND o.status IN

          #{status}

)

SELECT EXISTS(
    SELECT 1
    FROM wms_outbound_order o
    WHERE o.warehouse_id = #{warehouseId}
)
